import java.util.*; public class SmartClassroomAttendanceTracker{public static void mark(HashMap<String,ArrayList<String>>m,String sub,String stu){m.putIfAbsent(sub,new ArrayList<>());if(!m.get(sub).contains(stu))m.get(sub).add(stu);}public static void main(String[]a){HashMap<String,ArrayList<String>>m=new HashMap<>();mark(m,"Java","A");mark(m,"Java","A");mark(m,"DSA","B");for(String k:m.keySet()){System.out.println(k+":"+m.get(k));System.out.println("Total:"+m.get(k).size());}}}